"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
 import { Oswald } from 'next/font/google';

    const oswald = Oswald({
      subsets: ['lati'], // Specify the character subsets to load
      weight: ['600'], // Specify the desired font weights
      display: 'swap', // Control font loading behavior
    });


import { Kelly_Slab } from 'next/font/google';

const kellySlab = Kelly_Slab({
  subsets: ['latin'],
  weight: '400', 
  variable: '--font-kelly-slab',
});


type MenuItem = {
  _id?: string;
  name: string;
  description: string;
  price: number;
};

const categories = ["Food", "Drinks", "Brunch"];

export default function HomePage() {
  const [activeCategory, setActiveCategory] = useState("Food");
  const [items, setItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);

  // Fetch items whenever category changes
  useEffect(() => {
    async function fetchItems() {
      setLoading(true);
      try {
        const res = await fetch(
          `${process.env.NEXT_PUBLIC_API_BASE_URL}/menus/${activeCategory.toLowerCase()}`
        );
        const data = await res.json();
        setItems(data.items || []);
      } catch (err) {
        console.error(err);
        setItems([]);
      } finally {
        setLoading(false);
      }
    }

    fetchItems();
  }, [activeCategory]);

  return (
    <div className="w-full">
      
      {/* Hero Section with Overlay */}
      <section className="relative w-full h-[400px]">
  {/* Background image filling the whole section */}
  <Image
    src="/hero.jpg"
    alt="Hero Background"
    fill
    className="object-cover"
    priority
  />

  
  <div className="absolute inset-0 bg-gradient-to-r from-black/70 to-black/50 flex flex-col items-center justify-center text-center text-white px-4">
    <h2 className={`text-[70px] ${oswald.className}font-bold tracking-[0.03em] uppercase [text-shadow:1.8px_0.97px_0_#800020]`}>
  Menu
</h2>

    <p className="mt-2 font-kelly font-light text-[18px] max-w-[618px]">
      Please take a look at our menu featuring food, drinks, and brunch. If you'd like to place an order, use the "Order Online" button located below the menu.
    </p>
    <p className="mt-1 max-w-xl font-light">
     
    </p>
  </div>
</section>


   

{/* Category Tabs Section */}
<div className="relative h-[79px] w-full">
  {/* Background image */}
  <Image
    src="/main.png" // Put your actual image path here
    alt="Category Background"
    fill
    className="object-cover"
    priority // Optional: speeds up loading for important sections
  />

  {/* Gradient overlay */}
  <div className="absolute inset-0 bg-[#000000CC]" />

  {/* Content */}
  <div className="relative z-20 text-white flex justify-center gap-8 py-4">
    {categories.map((cat) => (
      <button
        key={cat}
        onClick={() => setActiveCategory(cat)}
        className={`uppercase font-oswald tracking-[0.03em] bg-black px-4 py-2 border font-medium  border-yellow-400 ${
          activeCategory === cat
            ? "bg-[#C5A059] "
            : "hover:border-b-2 hover:border-gray-400 [text-shadow:1.3px_0.97px_0_#800020]"
        }`}
      >
        {cat}
      </button>
    ))}
  </div>
</div>


<section className="relative w-full py-16 overflow-hidden min-h-[1000px] md:min-h-[1200px]">
  {/* Background Image */}
  <div className="absolute inset-0 -z-10">
    <Image
      src="/menubg.png"
      alt="Main Background"
      fill
      className="object-cover"
    />
    {/* Dark overlay */}
    <div className="absolute inset-0 bg-black/90">
  </div>

  {/* Side Decorations */}
  <Image
    src="/decor-left.png"
    alt="Left Decoration"
    width={200}
    height={400}
    className="absolute left-0 top-20 hidden md:block max-h-[80%] h-auto"
  />
  <Image
    src="/decor-right.png"
    alt="Right Decoration"
    width={200}
    height={400}
    className="absolute right-0 top-20 hidden md:block max-h-[80%] h-auto"
  />
  </div>

  {/* Content */}
  <div className="max-w-5xl mx-auto px-6">
    <div className="border border-yellow-600 p-8 relative">
      {/* Category Heading */}
      <h3 className="text-[40px] font-oswald font-semibold uppercase tracking-[0.03em] text-center text-white mb-10 [text-shadow:1.8px_0.97px_0_#800020]">
        {activeCategory}
      </h3>

      {loading ? (
        <p className="text-center text-white">Loading...</p>
      ) : items.length === 0 ? (
        <p className="text-center text-white">No items found.</p>
      ) : (
        <div className="grid md:grid-cols-2 gap-x-12 gap-y-6">
          {items.map((item) => (
            <div key={item._id || item.name} className="text-white ">
              <div className="flex justify-between items-center">
                <p className="font-oswald text-[22px] uppercase tracking-[0.03em] whitespace-nowrap">
                  {item.name}
                </p>
                <div className="flex-1 border-b border-dotted border-gray-500 mx-2"></div>
                <span className="font-oswald text-[22px] font-semibold tracking-[0.03em]">
                  ${item.price}
                </span>
              </div>
              <p className="text-gray-300 text-sm mt-1">{item.description}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  </div>
</section>


    </div>
  );
}
